1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = (x: number, y: number) => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isAlive && neighborCount === 2);
13	
14	type NeighborEntry = { cell: Cell; count: number; alive: boolean };
15	
16	function neighborhoodOf(cells: Cell[]): Map<string, NeighborEntry> {
17	  const neighborhood = new Map<string, NeighborEntry>();
18	  const touch = (x: number, y: number): NeighborEntry => {
19	    const k = keyOf(x, y);
20	    const entry = neighborhood.get(k) ?? { cell: [x, y], count: 0, alive: false };
21	    neighborhood.set(k, entry);
22	    return entry;
23	  };
24	  for (const [x, y] of cells) {
25	    touch(x, y).alive = true;
26	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
27	      touch(x + dx, y + dy).count++;
28	    }
29	  }
30	  return neighborhood;
31	}
32	
33	export function nextGeneration(cells: Cell[]): Cell[] {
34	  const result: Cell[] = [];
35	  for (const { cell, count, alive } of neighborhoodOf(cells).values()) {
36	    if (survives(alive, count)) {
37	      result.push(cell);
38	    }
39	  }
40	  return result;
41	}
