1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block stable (each cell has exactly 3 neighbors)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    const asSet = (cells: Array<[number, number]>) =>
18	      new Set(cells.map(([x, y]) => `${x},${y}`));
19	    expect(asSet(result)).toEqual(asSet(block));
20	  });
21	  it("transforms a vertical blinker into a horizontal blinker", () => {
22	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
23	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
24	    const asSet = (cells: Array<[number, number]>) =>
25	      new Set(cells.map(([x, y]) => `${x},${y}`));
26	    expect(asSet(nextGeneration(vertical))).toEqual(asSet(expected));
27	  });
28	  it("kills a live cell with 4 or more neighbors (overpopulation)", () => {
29	    // Pattern: ### / .#. / ### — center cell (1,1) has 4 live neighbors
30	    const cells: Array<[number, number]> = [
31	      [0, 0], [1, 0], [2, 0],
32	              [1, 1],
33	      [0, 2], [1, 2], [2, 2],
34	    ];
35	    const result = nextGeneration(cells);
36	    const asSet = (c: Array<[number, number]>) =>
37	      new Set(c.map(([x, y]) => `${x},${y}`));
38	    expect(asSet(result).has("1,1")).toBe(false);
39	  });
40	  it("brings a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
41	    // From prompt: ## / #. / .. → dead cell (1,1) has 3 live neighbors at (0,0),(1,0),(0,1)
42	    const cells: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
43	    const result = nextGeneration(cells);
44	    const asSet = (c: Array<[number, number]>) =>
45	      new Set(c.map(([x, y]) => `${x},${y}`));
46	    expect(asSet(result).has("1,1")).toBe(true);
47	  });
48	  it.todo("handles negative coordinates correctly");
49	});
